import React from 'react';
import { FiPackage, FiTruck, FiBriefcase, FiMapPin } from 'react-icons/fi';

const Home = () => {
  const ServiceCard = ({ icon: Icon, title, desc, color }) => (
    <div style={{
      flex: '1', minWidth: '250px', margin: '15px', padding: '30px',
      backgroundColor: 'rgba(255, 255, 255, 0.95)', borderRadius: '20px', textAlign: 'center',
      boxShadow: '0 10px 30px rgba(0,0,0,0.1)', borderTop: `6px solid ${color}`
    }}>
      <div style={{ fontSize: '3rem', color: color, marginBottom: '15px' }}><Icon /></div>
      <h5 style={{ fontWeight: 'bold', color: '#333' }}>{title}</h5>
      <p style={{ color: '#666', fontSize: '0.9rem' }}>{desc}</p>
      <button style={{ backgroundColor: color, color: 'white', border: 'none', padding: '10px 25px', borderRadius: '25px', fontWeight: 'bold' }}>Select</button>
    </div>
  );

  return (
    <div style={{ padding: '60px 20px' }}>
      <div style={{ textAlign: 'center', marginBottom: '50px' }}>
        <h1 style={{ fontSize: '2.8rem', fontWeight: '800', color: '#1a1a1a' }}>Apni Manzil Logistics</h1>
        <p style={{ fontSize: '1.2rem', color: '#0056b3', fontWeight: '600' }}>Aggregator Platform for MSMEs & Transporters</p>
      </div>
      <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', gap: '20px' }}>
        <ServiceCard icon={FiPackage} title="Courier Services" desc="Express Domestic Delivery" color="#2ecc71" />
        <ServiceCard icon={FiTruck} title="Transport" desc="Heavy Haulage & Trucking" color="#f1c40f" />
        <ServiceCard icon={FiBriefcase} title="Business MSME" desc="Bulk 3PL Solutions" color="#3498db" />
        <ServiceCard icon={FiMapPin} title="Live Tracking" desc="Real-time GPS Status" color="#e74c3c" />
      </div>
    </div>
  );
};

export default Home;
